transform.script:
const { artifactScope, contentDomain, artifactTypes, reasoning } = result;
const taskText = triggeringMessage.content?.text || '';
if (!taskText || !taskText.trim()) throw new Error('ISSUE_OPENED has no text content — nothing to review');

if (artifactScope === 'UNCERTAIN' || contentDomain === 'UNCERTAIN') {
  return {
    topic: 'CONDUCTOR_ESCALATE',
    content: {
      text: reasoning,
      data: { artifactScope, contentDomain, artifactTypes, reasoning, taskText }
    }
  };
}

const getTier = () => {
  if (artifactScope === 'CHAIN' && contentDomain === 'SENSITIVE') return 'axiom';
  if (artifactScope === 'CHAIN' || contentDomain === 'SENSITIVE') return 'vector';
  return 'trace';
};

const tier = getTier();
const tierParams = {
  trace:  { analyst_level: 'level2', validator_count: 1, max_iterations: 3, max_tokens: 100000 },
  vector: { analyst_level: 'level2', validator_count: 2, max_iterations: 4, max_tokens: 150000 },
  axiom:  { analyst_level: 'level3', validator_count: 2, max_iterations: 5, max_tokens: 150000 }
};

const has_test_content = artifactTypes.includes('test_suite') || artifactTypes.includes('acceptance_criteria');
const is_sensitive = contentDomain === 'SENSITIVE';
const is_chain = artifactScope === 'CHAIN';

const config = {
  base: 'docs-review-workflow',
  params: {
    tier,
    ...tierParams[tier],
    artifact_scope: artifactScope,
    content_domain: contentDomain,
    has_test_content,
    is_chain,
    is_sensitive
  }
};

return {
  topic: 'CLUSTER_OPERATIONS',
  content: {
    text: `[REVIEW:${tier.toUpperCase()}] ${reasoning}`,
    data: {
      operations: [
        { action: 'load_config', config },
        { action: 'publish', topic: 'ISSUE_OPENED', content: { text: taskText }, metadata: { _republished: true } }
      ]
    }
  }
};

const { artifactScope, contentDomain, artifactTypes, reasoning } = result;

let taskText = triggeringMessage.content?.data?.taskText || '';
if (!taskText) {
  taskText = triggeringMessage.content?.text || '';
}
if (!taskText) {
  const publishOp = triggeringMessage.content?.data?.operations?.find(op => op.action === 'publish');
  taskText = publishOp?.content?.text || '';
}

const getTier = () => {
  if (artifactScope === 'CHAIN' && contentDomain === 'SENSITIVE') return 'axiom';
  if (artifactScope === 'CHAIN' || contentDomain === 'SENSITIVE') return 'vector';
  return 'trace';
};

const tier = getTier();
const tierParams = {
  trace:  { analyst_level: 'level2', validator_count: 1, max_iterations: 3, max_tokens: 100000 },
  vector: { analyst_level: 'level2', validator_count: 2, max_iterations: 4, max_tokens: 150000 },
  axiom:  { analyst_level: 'level3', validator_count: 2, max_iterations: 5, max_tokens: 150000 }
};

const has_test_content = artifactTypes.includes('test_suite') || artifactTypes.includes('acceptance_criteria');
const is_sensitive = contentDomain === 'SENSITIVE';
const is_chain = artifactScope === 'CHAIN';

const config = {
  base: 'docs-review-workflow',
  params: {
    tier,
    ...tierParams[tier],
    artifact_scope: artifactScope,
    content_domain: contentDomain,
    has_test_content,
    is_chain,
    is_sensitive
  }
};

return {
  topic: 'CLUSTER_OPERATIONS',
  content: {
    text: `Senior: [REVIEW:${tier.toUpperCase()}] ${reasoning}`,
    data: {
      operations: [
        { action: 'load_config', config },
        { action: 'publish', topic: 'ISSUE_OPENED', content: { text: taskText }, metadata: { _republished: true } }
      ]
    }
  }
};
